import { create } from 'zustand'

const useSplitPaymentStore = create((set) => ({
    plans: [],
    totalAmount: 24000,
    activePlan: null,
    planSchedule: null,
    setActivePlan: (plan) => set(() => ({
        activePlan: plan
    })),
    setPlanSchedule: (scheduleList) => set((state) => ({
        planSchedule: [...scheduleList]
    })),
    setTotalAmount: (amnt) => set(() => ({
        totalAmount: amnt
    }))
}))

export default useSplitPaymentStore
